#!/usr/bin/env python3
# Piece 1c-calfix (dream-os) — the calendar year bug.
#
# kriya_calendar_add put a March shoot on 2026 (a date in the PAST) while the
# binder hand correctly resolved March -> 2027. Cause: the clock instruction read
# as binder-only, and the calendar hand never re-applied the next-occurrence rule.
#
# Fix is instruction-level (judgment, NOT logic-in-the-hand — cardinal rule):
#   * broaden the clock so it explicitly governs EVERY date Kriya writes — binder,
#     follow-up, calendar shoot, block — with "a shoot/booking is in the future,
#     never write a past date".
#   * nudge the calendar tool description to resolve dates against today.
#
# Overwrites kriyaTurn.js + kriyaCalendar.js.

import base64, os, sys
ROOT=os.getcwd()
PAYLOADS={
    'src/agent/kriyaTurn.js': '',
    'src/agent/kriyaCalendar.js': '',
}
def main():
    if not os.path.isdir(os.path.join(ROOT,"src","agent")):
        print("ERROR: run from dream-os repo root."); sys.exit(1)
    for rel,b64 in PAYLOADS.items():
        open(os.path.join(ROOT,rel),"wb").write(base64.b64decode(b64)); print(f"OK: overwrote {rel}")
    print("\nPiece 1c-calfix written. Calendar dates now resolve to the future, like binder dates.")
if __name__=="__main__": main()
